import{_ as a,c as e,b as o,o as i}from"./app-RrIk7Rat.js";const n={};function s(l,t){return i(),e("div",null,t[0]||(t[0]=[o('<h1 id="loadxmlmodal-component" tabindex="-1"><a class="header-anchor" href="#loadxmlmodal-component"><span>LoadXMLModal Component</span></a></h1><p>Displays a modal dialog for importing a IIIF manifest URL and converting it to an MEI file.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>The <code>LoadXMLModal</code> component:</p><ul><li>Shows a modal dialog for the user to input a IIIF manifest URL.</li><li>Provides a button to autofill a test IIIF manifest URL.</li><li>On import, triggers an action to convert the IIIF manifest to an MEI file for the Mercator app.</li><li>Modal can be closed with the Cancel button or overlay.</li><li>Uses Vuex store for state management and actions.</li></ul><hr><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><ul><li><strong>Header</strong>: Modal title (&quot;Lode IIIF&quot;) and close button.</li><li><strong>Body</strong>: <ul><li>Input field for IIIF manifest URL.</li><li>Description of the import process.</li><li>Button to autofill a test IIIF manifest URL.</li></ul></li><li><strong>Footer</strong>: Cancel and Import buttons.</li></ul><hr><h2 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>Props</span></a></h2><p><em>None</em></p><hr><h2 id="data" tabindex="-1"><a class="header-anchor" href="#data"><span>Data</span></a></h2><table><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>testUri</td><td>String</td><td>Example IIIF manifest URL for autofill</td></tr></tbody></table><hr><h2 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>useTestUri</td><td>Autofills the input with a test IIIF manifest URL</td></tr><tr><td>main</td><td>Triggers import action if the input is a valid URL, then closes the modal</td></tr><tr><td>closeModal</td><td>Closes the modal dialog</td></tr></tbody></table><hr><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><div class="language-vue line-numbers-mode" data-highlighter="prismjs" data-ext="vue"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>LoadXMLModal</span> <span class="token punctuation">/&gt;</span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div>',21)]))}const d=a(n,[["render",s]]),h=JSON.parse('{"path":"/technical/LoadXMLModal.html","title":"LoadXMLModal Component","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756211745000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":2,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"},{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"technical/LoadXMLModal.md"}');export{d as comp,h as data};
